<template>
  <div class="add-body">
    <!--main-->
    <div class="add-content">
      <!--con-->
      <div class="add-content_row" style="height: 4vh;padding-top:2vh">
        <div class="add-content_col" style="width: 50%;">
          <span><i>*</i>角色名称</span>
          <span>
            <el-input
                v-model="roleForm['roleName']" @input="$forceUpdate()"></el-input>
          </span>
        </div>
        <div class="add-content_col" style="width: 50%;">
          <span>角色描述</span>
          <span>
            <el-input
                v-model="roleForm['remarks']" @input="$forceUpdate()"></el-input>
          </span>
        </div>
      </div>
      <!--菜单权限-->
      <div class="body-con-title">
        <img src="~@/assets/image/srm-circle.png" style="width: 15px;margin-right: 1vh;">菜单权限
      </div>
      <div class="body-con-tree">
        <el-tree
            ref="menuTree"
            :data="menuData"
            show-checkbox
            default-expand-all
            node-key="menuId"
            check-on-click-node
            :props="defaultProps"
            check-strictly
            @check="nodeCheck">
           <span slot-scope="{ node, data }">
      <i :class="data.icon"></i>
      <span style="padding-left: 4px;">{{ node.label }}</span>
    </span>
        </el-tree>

        <!--菜单权限END!-->
      </div>
      <!--===-->
    </div>
    <!--按钮-->
    <div class="add-btn-box">
      <div class="add-btn" @click="$emit('CloseDialog')">取 消</div>
      <div class="add-btn" @click="addRole()">保 存</div>
    </div>
    <!--到底啦！===========================-->
  </div>
</template>
<script>
import * as roleAddApi from "@/api/System/role.js"

export default {
  name: "addRole",
  props: ['RoleMsg'],
  data() {
    return {

      roleForm: {},
      menuData: [
        // {
        //   name: '事件监管', isSelect: false, isChildrenSelect: false,children: [
        //     {name: '报警事件',children: [
        //         {name: '新增',icon:'el-icon-s-tools'},
        //         {name: '修改',icon:'el-icon-s-tools'},
        //       ]},
        //     {name: '访客事件'},
        //   ]
        // },
        // {name: '视频监控', isSelect: false, isChildrenSelect: false, children: [
        //     {name: '实时视频'},
        //     {name: '视频回看'},
        //   ]
        // },
        // {name: '智能识别', isSelect: false, isChildrenSelect: false, children: [
        //     {name: '识别配置'},
        //     {name: '识别详情'},
        //   ]
        // },
        // {name: '智能控制', isSelect: false},
        // {name: '设备管理', isSelect: false, isChildrenSelect: false, children: [
        //     {name: '摄像头管理'},
        //     {name: '边缘设备管理'},
        //   ]
        // },
        // {
        //   name: '系统管理', isSelect: false, isChildrenSelect: false, children: [
        //     {name: '用户管理',path:'/User'},
        //     {name: '角色管理',path:'/Role'},
        //     {name: '日志管理'},
        //   ]
        // },
      ],
      defaultProps: {
        children: 'childMenuArray',
        label: 'name'
      },
      title: "新建角色",
      checkMenuDataId: []
    }
  },
  created() {
    this.getMenu()
    if (this.RoleMsg.title == 'edit') {

      this.roleForm.roleName = this.RoleMsg.row.roleName
      this.roleForm.remarks = this.RoleMsg.row.remarks
      this.$forceUpdate()
      this.getRoleMsg()
    }
  },
  methods: {
    //获取菜单
    getMenu() {
      roleAddApi.queryMenuApi({type: 2}).then(res => {

        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        this.menuData = res.data.result
      })
    },

    //新增角色
    addRole() {
      if (!this.roleForm.roleName) return this.$message.error({
        message: "角色名称不能为空！",
        showClose: true,
        duration: 1000
      });
      //...this.$refs.menuTree.getHalfCheckedKeys(),
      var menuId = [...this.$refs.menuTree.getCheckedKeys()]

      var params = {
        ids: [],
        roleName: this.roleForm.roleName,
        isPreset: 0,
        remarks: this.roleForm.remarks
      }
      menuId.forEach(item => {
        params.ids.push(item)
      })
      if (this.RoleMsg.title == 'edit') {//编辑角色
        params.id = this.RoleMsg.row.id
        roleAddApi.updateRoleApi(params).then(res => {
          if (res.data.code != '2000') return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000
          });
          this.$message.success({message: "编辑角色成功", showClose: true, duration: 1000});
          // this.$router.push('/system/roleAdmin')
          this.$emit('CloseDialog', 0)
        })
      } else {//新建角色
        roleAddApi.addRoleApi(params).then(res => {
          if (res.data.code != '2000') return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000
          });
          this.$message.success({message: "新建角色成功", showClose: true, duration: 1000});
          this.$emit('CloseDialog', 0)
        })
      }
    },
    //获取角色信息
    getRoleMsg() {
      roleAddApi.queryMenuIdsApi({id: this.RoleMsg.row.id}).then(res => {

        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        if (res.data.result.length != 0) {
          this.$refs.menuTree.setCheckedKeys(res.data.result)
        }

      })
    },
    list(data) {
      data.forEach(item => {
        if (!item.list) {
          this.checkMenuDataId.push(item.menuId)
        } else {
          this.list(item.list)
        }
      })
    },
    //
    nodeCheck(data) {
      console.log(data);
      const node = this.$refs.menuTree.getNode(data.menuId);
      this.setNode(node);
    },
    setNode(node) {
      console.log(node, "node");
      if (node.checked) {
        //如果当前是选中checkbox,则递归设置父节点和父父节点++选中
        this.setParentNode(node);
      } else {
        //当前是取消选中,将所有子节点都取消选中
        this.setChildenNode(node);
      }
    },
    setParentNode(node) {
      if (node.parent) {
        for (const key in node) {
          if (key === "parent") {
            node[key].checked = true;
            this.setParentNode(node[key]);
          }
        }
      }
    },
    setChildenNode(node) {
      let len = node.childNodes.length;
      for (let i = 0; i < len; i++) {
        node.childNodes[i].checked = false;
        this.setChildenNode(node.childNodes[i]);
      }
    },
  }
}
</script>

<style scoped lang="scss">
.add-body {


  .body-con-title {
    width: 100%;
    font-size: 17px;
    color: #ffffff;
    text-align: left;
    font-weight: bold;
    letter-spacing: 2px;
    margin-bottom: 10px;
    margin-left: 1vw;
    margin-top: 0;
    text-shadow: 0px 4px 0px rgba(10, 40, 95, 0.36);

    background: linear-gradient(0deg, #ffffff 0%, #98deff 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    display: flex;
    align-items: center;

    &.newtitle {
      text-shadow: none !important;
      background: none !important;
      color: #ffffff !important;
      font-weight: normal;
      font-size: 14px;
      -webkit-text-fill-color: #ffffff !important;
    }
  }

  .body-con-tree {
    width: 80%;
    margin: 0 auto;
    height: calc(100% - 15vh);
    overflow: auto;
    background: rgba(0, 31, 63, 0.6);
    border: 2px solid rgba(12, 187, 200, 0.8);
    box-shadow: 0px 0px 13px 0px rgba(2, 138, 185, 0.25);
  }

  .body-con-tree::-webkit-scrollbar {
    width: 0;
  }
}
</style>