-->
<template>
  <div class="Role-body">
    <LTPages
        :title="'角色管理'"
        :isNormal="false"
        :formConfig="formConfig"
        :buttonConfig="buttonConfig"
        :tableConfig="tableConfig"
        @setSearchFields="getSearchFields"
        @tablePageForm="getTableForm"
        @setSelectionTable="getSelectionTable"
    ></LTPages>
    <!--新增角色===============-->
    <LTDialog
        v-if="RoleMsg.isShow"
        :DialogLTMsg="RoleMsg"
        @close="RoleMsg.isShow = false">
      <addRole :role-msg="RoleMsg" @CloseDialog="CloseDialog"></addRole>
    </LTDialog>
    <!--到底啦！===============-->
  </div>
</template>

<script>

import * as RoleApi from "@/api/System/role.js"
import addRole from "./components/addRole.vue";
export default {
  name: "Role",
  components: {
    addRole
  },
  data() {
    return {
      //搜索配置
      formConfig: {
        itemNum: 5,
        labelWidth: '80px',
        formItemList: [
          {
            id: 1,
            type: 'text',
            prop: 'roleName',
            label: '角色名称',
            value: ''
          }
        ]
      },
      // 按钮
      buttonConfig: [
        {
          label: '添加',
          icon: "icon zhb-iconfont zhb-iconzengjia",
          click: () => {
            this.RoleMsg.type = 'add'
            this.RoleMsg.title = '新增角色'
            this.RoleMsg.isShow = true;
          }
        },
        {
          label: '删除',
          icon: "icon zhb-iconfont zhb-iconshanchu2",
          click: () => {
            if (this.checkTabelData.length == 0) return this.$message.warning({
              message: "请至少选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            if (this.checkTabelData[0].isPreset == 1) return this.$message.warning({
              message: "系统预制角色不可删除！",
              showClose: true,
              duration: 1000
            });
            this.$confirm('此操作将永久删除该角色, 是否继续?', '提示', {
              confirmButtonText: '确定',
              cancelButtonText: '取消',
              type: 'warning'
            }).then(() => {

              var ids = []
              this.checkTabelData.forEach(item => {
                ids.push(item.id)
              })
              RoleApi.deleteRoleApi({ids: ids}).then(res => {
                if (res.data.code != '2000') return this.$message.error({
                  message: res.data.message,
                  showClose: true,
                  duration: 1000
                });
                this.queryRole()
                this.$message({
                  type: 'success',
                  message: '删除成功！'
                });
              })
            }).catch(() => {
              this.$message({
                type: 'info',
                message: '已取消删除'
              });
            });
          }
        }
      ],
      //表格配置
      tableConfig: {
        tableRefresh: true,
        tableHead: [
          {
            label: '角色名称',
            prop: 'roleName',
          },
          {
            label: '角色描述',
            prop: 'remarks',
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [],
        columnButton: [],
        columnWidth: '130',
        // tableColWidth:'155',
        total: 0,
        pageSize: 20,
        currentPage: 1,
      },
      //表格勾选
      checkTabelData: [],
      //查询参数
      params: {
        pageSize: 20,
        currentPage: 1,
      },
      RoleMsg: {
        isShow: false,
        title: '添加角色',
        showCloseBtn: true,
        styles: {
          width: '50%',
          height: '80%'
        }
      }
    };
  },
  created() {
    this.queryRole();
  },
  methods: {
    getSearchFields(data) {
      console.log(data);
      if (data.type != 'reset') {
        this.params.roleName = data.roleName
        this.params.currentPage = 1;
        this.tableConfig.currentPage = 1;
      } else { //重置
        this.params = {
          pageSize: 20,
          currentPage: 1
        }
      }
      this.queryRole();
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.params.pageSize = page.pageSize;
      this.params.currentPage = page.pageNum;
      this.queryRole();
    },
    // 勾选
    getSelectionTable(val) {
      this.checkTabelData = val;
    },
    // 查询
    queryRole() {
      RoleApi.queryRoleApi(this.params).then(res => {

        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        this.tableConfig.tableData = res.data.result.records
        this.tableConfig.total = res.data.result.total
      })
    },
    // 关闭弹窗
    CloseDialog(val) {
      if (val == 0) {
        this.RoleMsg.isShow = false;
        this.queryRole()
      } else {
        this.RoleMsg.isShow = false;
      }
    }


  }
}
</script>

<style scoped lang="scss">
  .Role-body{
    width: 100%;
    height: 100%;
  }
</style>